import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { useAuth } from './contexts/AuthContext';
import Login from './pages/Login';
import AdminSupremo from './pages/AdminSupremo';
import Suporte from './pages/Suporte';
import Sub from './pages/Sub';
import LoadingSpinner from './components/LoadingSpinner';

function App() {
  const { isAuthenticated, loading, admin } = useAuth();

  if (loading) {
    return <LoadingSpinner />;
  }

  if (!isAuthenticated) {
    return <Login />;
  }

  // Redirecionamento baseado no nível do admin
  const getDashboardRoute = () => {
    switch (admin?.nivel) {
      case 'supreme':
        return '/admin-supremo';
      case 'atendente':
        return '/suporte';
      case 'revendedor':
        return '/sub';
      default:
        return '/login';
    }
  };

  return (
    <Routes>
      <Route path="/login" element={<Navigate to={getDashboardRoute()} replace />} />
      <Route 
        path="/admin-supremo/*" 
        element={
          admin?.nivel === 'supreme' ? 
          <AdminSupremo /> : 
          <Navigate to={getDashboardRoute()} replace />
        } 
      />
      <Route 
        path="/suporte/*" 
        element={
          admin?.nivel === 'atendente' ? 
          <Suporte /> : 
          <Navigate to={getDashboardRoute()} replace />
        } 
      />
      <Route 
        path="/sub/*" 
        element={
          admin?.nivel === 'revendedor' ? 
          <Sub /> : 
          <Navigate to={getDashboardRoute()} replace />
        } 
      />
      <Route path="/" element={<Navigate to={getDashboardRoute()} replace />} />
      <Route path="*" element={<Navigate to={getDashboardRoute()} replace />} />
    </Routes>
  );
}

export default App;
